// Get the incoming data from the previous node
const data = $input.first().json;

// ============================================
// STEP 1: Build Comprehensive Log Entry
// ============================================
const logEntry = {
  // Workflow metadata
  workflowName: 'aws-security-containment',
  workflowVersion: '1.0.0',
  timestamp: new Date().toISOString(),
  executionId: data.executionId || 'unknown',

  // Alert details
  sirtID: data.sirtID || 'SIR-UNKNOWN',
  alertType: data.alertType || 'Unknown',
  alertDescription: data.alertDescription || '',
  alertSource: data.findingSource || 'GuardDuty',
  severity: data.severity || 0,

  // Resource details
  resourceType: data.resourceType || 'unknown',
  resourceId: data.resourceId || 'unknown',
  resourceArn: data.resourceArn || '',
  accountId: data.accountId || 'unknown',
  region: data.region || 'us-east-1',

  // Lambda execution
  lambdaFunction: data.functionName || 'unknown',
  lambdaPayload: data.lambdaPayload || {},
  lambdaResponse: data.lambdaResponse || {},
  lambdaParsedResponse: data.parsedResponse || {},

  // Containment details
  containmentStatus: data.executionStatus || 'unknown',
  containmentActions: data.containmentDetails?.details || [],
  needsManualIntervention: data.needsManualIntervention || false,
  manualInterventionReason: data.manualInterventionReason || '',

  // Error handling
  errorMessage: data.errorMessage || null,

  // Summary
  summary: data.summary || 'No summary available',

  // Additional metadata
  slackText: data.slackText || '',
  tags: ['security', 'containment', 'automated-response']
};

// ============================================
// STEP 2: Build CloudWatch Log Formats
// ============================================

// 2a: JSON Log (structured for CloudWatch)
const jsonLog = JSON.stringify(logEntry);

// 2b: Human-Readable Log (for CloudWatch console)
let humanReadableLog = '========================================\n';
humanReadableLog += 'AWS SECURITY - CONTAINMENT LOG\n';
humanReadableLog += '========================================\n\n';
humanReadableLog += 'Timestamp: ' + logEntry.timestamp + '\n';
humanReadableLog += 'SIR ID: ' + logEntry.sirtID + '\n';
humanReadableLog += 'Execution ID: ' + logEntry.executionId + '\n\n';

humanReadableLog += '--- ALERT DETAILS ---\n';
humanReadableLog += 'Type: ' + logEntry.alertType + '\n';
humanReadableLog += 'Source: ' + logEntry.alertSource + '\n';
humanReadableLog += 'Severity: ' + logEntry.severity + '\n';
humanReadableLog += 'Description: ' + logEntry.alertDescription + '\n\n';

humanReadableLog += '--- RESOURCE DETAILS ---\n';
humanReadableLog += 'Type: ' + logEntry.resourceType + '\n';
humanReadableLog += 'ID: ' + logEntry.resourceId + '\n';
humanReadableLog += 'Account: ' + logEntry.accountId + '\n';
humanReadableLog += 'Region: ' + logEntry.region + '\n\n';

humanReadableLog += '--- CONTAINMENT ---\n';
humanReadableLog += 'Status: ' + logEntry.containmentStatus + '\n';
humanReadableLog += 'Lambda: ' + logEntry.lambdaFunction + '\n';
if (logEntry.containmentActions.length > 0) {
  humanReadableLog += 'Actions:\n';
  for (let i = 0; i < logEntry.containmentActions.length; i++) {
    humanReadableLog += '  - ' + logEntry.containmentActions[i] + '\n';
  }
}
humanReadableLog += '\n';

if (logEntry.needsManualIntervention) {
  humanReadableLog += '⚠️ MANUAL INTERVENTION REQUIRED!\n';
  humanReadableLog += 'Reason: ' + logEntry.manualInterventionReason + '\n\n';
}

if (logEntry.errorMessage) {
  humanReadableLog += '❌ ERROR:\n';
  humanReadableLog += logEntry.errorMessage + '\n\n';
}

humanReadableLog += 'Summary: ' + logEntry.summary + '\n';
humanReadableLog += '========================================\n';

// ============================================
// STEP 3: Prepare CloudWatch Log Events
// ============================================
const timestamp = Date.now();

// 3a: Single log event (JSON)
const cloudwatchJsonEvent = {
  logGroupName: '/aws/security/containment',
  logStreamName: logEntry.region + '/' + logEntry.accountId,
  logEvents: [{
    timestamp: timestamp,
    message: jsonLog
  }]
};

// 3b: Multiple log events (JSON + Human-readable)
const cloudwatchEvents = {
  logGroupName: '/aws/security/containment',
  logStreamName: logEntry.region + '/' + logEntry.accountId,
  logEvents: [
    {
      timestamp: timestamp,
      message: jsonLog
    },
    {
      timestamp: timestamp + 1,
      message: humanReadableLog
    }
  ]
};

// 3c: With severity-based filtering (for CloudWatch Insights)
const cloudwatchStructuredLog = {
  logGroupName: '/aws/security/containment',
  logStreamName: logEntry.region + '/' + logEntry.accountId,
  logEvents: [{
    timestamp: timestamp,
    message: JSON.stringify({
      ...logEntry,
      // Add severity level for CloudWatch Logs Insights
      logLevel: logEntry.severity >= 7 ? 'HIGH' : 
                logEntry.severity >= 4 ? 'MEDIUM' : 'LOW',
      status: logEntry.containmentStatus,
      // Add for easier querying
      '@timestamp': logEntry.timestamp,
      '@message': jsonLog
    })
  }]
};

// ============================================
// STEP 4: Return Data for CloudWatch Upload
// ============================================
return [{
  json: {
    // Original data
    ...data,

    // Log entries
    logEntry: logEntry,
    jsonLog: jsonLog,
    humanReadableLog: humanReadableLog,

    // CloudWatch configurations
    cloudwatch: {
      logGroupName: '/aws/security/containment',
      logStreamName: logEntry.region + '/' + logEntry.accountId,
      region: logEntry.region,
      accountId: logEntry.accountId
    },

    // CloudWatch log events (choose one)
    cloudwatchJsonEvent: cloudwatchJsonEvent,
    cloudwatchEvents: cloudwatchEvents,
    cloudwatchStructuredLog: cloudwatchStructuredLog,

    // For individual log event (AWS CloudWatch Logs node)
    logGroupName: '/aws/security/containment',
    logStreamName: logEntry.region + '/' + logEntry.accountId,
    logEvent: {
      timestamp: timestamp,
      message: jsonLog
    },

    // Status
    logged: true,
    logTimestamp: logEntry.timestamp,
    logSummary: 'Logged containment for ' + logEntry.sirtID + ' (' + logEntry.resourceId + ')'
  }
}];

// Get the incoming data from the previous node
const data = $input.first().json;

// ============================================
// STEP 1: Build Comprehensive Log Entry
// ============================================
const logEntry = {
  // Workflow metadata
  workflowName: 'aws-security-containment',
  workflowVersion: '1.0.0',
  timestamp: new Date().toISOString(),
  executionId: data.executionId || 'unknown',

  // Alert details
  sirtID: data.sirtID || 'SIR-UNKNOWN',
  alertType: data.alertType || 'Unknown',
  alertDescription: data.alertDescription || '',
  alertSource: data.findingSource || 'GuardDuty',
  severity: data.severity || 0,

  // Resource details
  resourceType: data.resourceType || 'unknown',
  resourceId: data.resourceId || 'unknown',
  resourceArn: data.resourceArn || '',
  accountId: data.accountId || 'unknown',
  region: data.region || 'us-east-1',

  // Lambda execution
  lambdaFunction: data.functionName || 'unknown',
  lambdaPayload: data.lambdaPayload || {},
  lambdaResponse: data.lambdaResponse || {},
  lambdaParsedResponse: data.parsedResponse || {},

  // Containment details
  containmentStatus: data.executionStatus || 'unknown',
  containmentActions: data.containmentDetails?.details || [],
  needsManualIntervention: data.needsManualIntervention || false,
  manualInterventionReason: data.manualInterventionReason || '',

  // Error handling
  errorMessage: data.errorMessage || null,

  // Summary
  summary: data.summary || 'No summary available',

  // Additional metadata
  slackText: data.slackText || '',
  tags: ['security', 'containment', 'automated-response']
};

// ============================================
// STEP 2: Build Splunk Log Formats
// ============================================

// 2a: Single event (for Splunk HEC)
const splunkSingleEvent = {
  event: logEntry,
  sourcetype: 'aws-security-containment',
  index: 'security',
  source: 'n8n-workflow',
  host: 'aws-containment-automation'
};

// 2b: Multiple events (batch mode)
const splunkBatchEvents = {
  events: [
    {
      event: logEntry,
      sourcetype: 'aws-security-containment',
      index: 'security',
      source: 'n8n-workflow',
      host: 'aws-containment-automation'
    }
  ]
};

// 2c: Raw data format (for non-JSON endpoints)
const splunkRawEvent = {
  event: JSON.stringify(logEntry),
  sourcetype: 'json',
  index: 'security'
};

// 2d: With custom metadata (for Splunk search optimization)
const splunkEnhancedEvent = {
  event: {
    ...logEntry,
    // Add Splunk-optimized fields
    severity_level: logEntry.severity >= 7 ? 'critical' : 
                     logEntry.severity >= 4 ? 'high' : 'medium',
    resource_category: logEntry.resourceType,
    containment_required: logEntry.needsManualIntervention ? 'yes' : 'no',
    execution_time: new Date().toISOString()
  },
  sourcetype: 'aws-security-containment',
  index: 'security',
  source: 'n8n-workflow',
  host: 'aws-containment-automation'
};

// ============================================
// STEP 3: Build Splunk-Friendly Log Formats
// ============================================

// 3a: JSON for Splunk (structured)
const splunkJsonLog = JSON.stringify(logEntry);

// 3b: Human-readable for Splunk (for free text search)
let splunkHumanReadable = 'TIMESTAMP=' + logEntry.timestamp + ' ';
splunkHumanReadable += 'SIR_ID=' + logEntry.sirtID + ' ';
splunkHumanReadable += 'RESOURCE_TYPE=' + logEntry.resourceType + ' ';
splunkHumanReadable += 'RESOURCE_ID=' + logEntry.resourceId + ' ';
splunkHumanReadable += 'ACCOUNT=' + logEntry.accountId + ' ';
splunkHumanReadable += 'REGION=' + logEntry.region + ' ';
splunkHumanReadable += 'SEVERITY=' + logEntry.severity + ' ';
splunkHumanReadable += 'STATUS=' + logEntry.containmentStatus + ' ';
splunkHumanReadable += 'LAMBDA=' + logEntry.lambdaFunction + ' ';
if (logEntry.errorMessage) {
  splunkHumanReadable += 'ERROR=' + logEntry.errorMessage + ' ';
}
splunkHumanReadable += 'SUMMARY=' + logEntry.summary;

// 3c: Key-Value format (Splunk default)
let splunkKeyValue = '';
for (const [key, value] of Object.entries(logEntry)) {
  if (value !== null && value !== undefined) {
    if (typeof value === 'object') {
      splunkKeyValue += key + '=' + JSON.stringify(value) + ' ';
    } else {
      splunkKeyValue += key + '=' + value + ' ';
    }
  }
}

// ============================================
// STEP 4: Prepare Splunk HEC Configurations
// ============================================

// Splunk HEC configuration (for HTTP Request node)
const splunkConfig = {
  endpoint: 'https://your-splunk-instance:8088/services/collector',
  authHeader: 'Splunk YOUR_HEC_TOKEN', // Replace with your actual token
  headers: {
    'Authorization': 'Splunk YOUR_HEC_TOKEN',
    'Content-Type': 'application/json'
  },
  // Use one of the event formats above
  body: splunkSingleEvent
};

// ============================================
// STEP 5: Return Data for Splunk Upload
// ============================================
return [{
  json: {
    // Original data
    ...data,

    // Log entries
    logEntry: logEntry,
    splunkJsonLog: splunkJsonLog,
    splunkHumanReadable: splunkHumanReadable,
    splunkKeyValue: splunkKeyValue,

    // Splunk event formats
    splunkSingleEvent: splunkSingleEvent,
    splunkBatchEvents: splunkBatchEvents,
    splunkEnhancedEvent: splunkEnhancedEvent,

    // Splunk configuration
    splunkConfig: splunkConfig,
    splunkEndpoint: 'https://your-splunk-instance:8088/services/collector',
    splunkAuthHeader: 'Splunk YOUR_HEC_TOKEN',

    // For quick copy-paste
    splunkRawBody: JSON.stringify(splunkSingleEvent),

    // Status
    logged: true,
    logTimestamp: logEntry.timestamp,
    logSummary: 'Logged containment for ' + logEntry.sirtID + ' (' + logEntry.resourceId + ')'
  }
}];

// Get the incoming data from the webhook
const data = $input.first().json;

// --- Assume the Wiz finding is directly at $input.first().json ---
const finding = data;

// --- Initialize Variables ---
let resourceId = null;
let resourceType = null;
let resourceArn = null;
let accountId = null;
let severity = null;
let alertType = null;
let alertDescription = null;
let region = null;
let provider = 'unknown'; // aws, gcp, azure
let findingSource = 'Wiz';
let needsContainment = false;
let rawResourceId = null;

// --- Helper: Extract provider from ARN/ID ---
function detectProvider(arn) {
  if (!arn) return 'unknown';
  if (arn.startsWith('arn:aws:')) return 'aws';
  if (arn.startsWith('arn:gcp:')) return 'gcp';
  if (arn.startsWith('arn:azure:') || arn.startsWith('/subscriptions/')) return 'azure';
  return 'unknown';
}

// --- Parse Wiz Finding ---
// Example: Vulnerability Finding (CVE)
if (finding.vulnerableAsset) {
  alertType = finding.name || 'CVE';
  alertDescription = finding.CVEDescription || finding.description || 'Vulnerability finding';
  severity = finding.severity; // CRITICAL, HIGH, MEDIUM, LOW
  const asset = finding.vulnerableAsset;

  // Extract Resource Information
  if (asset.providerUniqueId) {
    resourceArn = asset.providerUniqueId;
    provider = detectProvider(resourceArn);

    // Extract resourceId from ARN
    const arnParts = resourceArn.split(':');
    if (arnParts.length > 5) {
      const resourcePart = arnParts[5];
      const resourceParts = resourcePart.split('/');
      resourceId = resourceParts[resourceParts.length - 1];
      rawResourceId = resourceId;
    }
  }

  resourceType = asset.type || 'VIRTUAL_MACHINE';
  region = asset.region;
  accountId = asset.subscriptionExternalId;

  // Determine containment based on severity
  if (severity === 'CRITICAL' || severity === 'HIGH') {
    needsContainment = true;
  }
}

// --- Parse CSPM Finding (Network Exposure, Misconfiguration) ---
else if (finding.ruleName) {
  alertType = finding.ruleName;
  alertDescription = finding.remediationNotes || finding.description || 'CSPM finding';
  severity = finding.severity;
  accountId = finding.targetAccountIdentifier || finding.subscriptionId;
  region = finding.targetRegion || finding.region;
  resourceId = finding.targetResourceIdentifier || finding.resourceId;
  rawResourceId = resourceId;
  resourceType = finding.targetResourceSubtype || finding.resourceType || 'Resource';

  // Detect provider
  if (finding.targetAccountType) {
    provider = finding.targetAccountType.toLowerCase(); // aws, gcp, azure
  } else if (finding.targetResourceIdentifier) {
    provider = detectProvider(finding.targetResourceIdentifier);
  }

  if (finding.result === 'FAIL' || finding.status === 'OPEN') {
    needsContainment = true;
  }
}

// --- Parse Malware Finding ---
else if (finding.malware) {
  alertType = finding.malware.name || 'Malware Detected';
  alertDescription = finding.malware.description || finding.description;
  severity = finding.severity || 'CRITICAL';

  if (finding.resource) {
    resourceArn = finding.resource.providerUniqueId;
    provider = detectProvider(resourceArn);
    resourceId = finding.resource.name || finding.resource.id;
    rawResourceId = resourceId;
    resourceType = finding.resource.type || 'Resource';
    region = finding.resource.region;
    accountId = finding.resource.subscriptionId;
    needsContainment = true; // Malware always needs containment
  }
}

// --- Fallback: Try to detect provider from any ARN-like field ---
else {
  // Try to find an ARN in the finding
  const arnKeys = ['arn', 'resourceArn', 'providerUniqueId', 'targetResourceIdentifier'];
  for (const key of arnKeys) {
    if (finding[key]) {
      const potentialArn = finding[key];
      provider = detectProvider(potentialArn);
      if (provider !== 'unknown') {
        resourceArn = potentialArn;
        // Extract resourceId from ARN
        const arnParts = potentialArn.split(':');
        if (arnParts.length > 5) {
          const resourcePart = arnParts[5];
          const resourceParts = resourcePart.split('/');
          resourceId = resourceParts[resourceParts.length - 1];
          rawResourceId = resourceId;
        }
        break;
      }
    }
  }

  // Try to get other fields
  alertType = finding.type || finding.findingType || 'Security Finding';
  alertDescription = finding.description || finding.message || 'Security alert from Wiz';
  severity = finding.severity || finding.riskLevel || 'MEDIUM';
  accountId = finding.accountId || finding.subscriptionId || finding.projectId;
  region = finding.region || finding.location;
  resourceType = finding.resourceType || finding.assetType || 'Resource';

  if (severity === 'CRITICAL' || severity === 'HIGH') {
    needsContainment = true;
  }
}

// --- Provider-specific Resource Type Normalization ---
// For AWS
if (provider === 'aws') {
  if (resourceType === 'VIRTUAL_MACHINE' || resourceType === 'EC2Instance') {
    resourceType = 'ec2-instance';
  } else if (resourceType === 'S3Bucket') {
    resourceType = 's3-bucket';
  } else if (resourceType === 'IAMUser') {
    resourceType = 'iam-user';
  } else if (resourceType === 'IAMRole') {
    resourceType = 'iam-role';
  } else if (resourceType === 'LambdaFunction') {
    resourceType = 'lambda-function';
  } else if (resourceType === 'RDSInstance') {
    resourceType = 'rds-instance';
  }
}

// For GCP
if (provider === 'gcp') {
  if (resourceType === 'VIRTUAL_MACHINE' || resourceType === 'GCEInstance') {
    resourceType = 'gce-instance';
  } else if (resourceType === 'GCSBucket') {
    resourceType = 'gcs-bucket';
  } else if (resourceType === 'CloudFunction') {
    resourceType = 'gcp-cloud-function';
  } else if (resourceType === 'BigQueryDataset') {
    resourceType = 'bigquery-dataset';
  } else if (resourceType === 'CloudSQLInstance') {
    resourceType = 'cloudsql-instance';
  }
}

// For Azure
if (provider === 'azure') {
  if (resourceType === 'VIRTUAL_MACHINE' || resourceType === 'AzureVM') {
    resourceType = 'azure-vm';
  } else if (resourceType === 'StorageAccount') {
    resourceType = 'azure-storage';
  } else if (resourceType === 'FunctionApp') {
    resourceType = 'azure-function';
  } else if (resourceType === 'SQLDatabase') {
    resourceType = 'azure-sql';
  } else if (resourceType === 'KeyVault') {
    resourceType = 'azure-keyvault';
  }
}

// --- Prepare Output ---
return [{
  json: {
    messageType: 'Notification',
    provider: provider,
    resourceType: resourceType,
    resourceId: resourceId,
    rawResourceId: rawResourceId,
    resourceArn: resourceArn,
    accountId: accountId,
    region: region,
    severity: severity,
    needsContainment: needsContainment,
    alertType: alertType,
    alertDescription: alertDescription,
    findingSource: findingSource,
    finding: finding,
    alertSummary: `[${findingSource}] ${alertType} on ${provider}:${resourceType} (${resourceId})`
  }
}];

// Fallback
return [{
  json: {
    messageType: 'Unknown',
    data: finding
  }
}];

// Get the incoming data
const data = $input.first().json;

// ============================================
// STEP 1: Extract Provider
// ============================================
const provider = data.provider || 'unknown';

// ============================================
// STEP 2: Map Resource Types to Function Names by Provider
// ============================================

// AWS Lambda function mappings
const awsFunctionMap = {
  'ec2-instance': 'contain-ec2-instance',
  's3-bucket': 'contain-s3-bucket',
  'iam-user': 'contain-iam-user',
  'iam-role': 'contain-iam-role',
  'lambda-function': 'contain-lambda-function',
  'rds-instance': 'contain-rds-instance',
  'access-key': 'contain-access-key',
  'sts-session': 'contain-sts-session'
};

// GCP Cloud Function mappings
const gcpFunctionMap = {
  'gce-instance': 'contain-gce-instance',
  'gcs-bucket': 'contain-gcs-bucket',
  'gcp-cloud-function': 'contain-gcp-cloud-function',
  'bigquery-dataset': 'contain-bigquery-dataset',
  'cloudsql-instance': 'contain-cloudsql-instance'
};

// Azure Function mappings
const azureFunctionMap = {
  'azure-vm': 'contain-azure-vm',
  'azure-storage': 'contain-azure-storage',
  'azure-function': 'contain-azure-function',
  'azure-sql': 'contain-azure-sql',
  'azure-keyvault': 'contain-azure-keyvault'
};

// ============================================
// STEP 3: Build Provider-Specific Payloads
// ============================================

function buildAWSPayload(data) {
  return {
    targetResourceId: data.resourceId,
    targetAccount: data.accountId,
    targetRegion: data.region,
    sirtID: data.sirtID || 'SIR-UNKNOWN',
    severity: data.severity,
    alertType: data.alertType,
    alertDescription: data.alertDescription,
    resourceType: data.resourceType,
    // AWS-specific fields
    arn: data.resourceArn,
    rawResourceId: data.rawResourceId
  };
}

function buildGCPPayload(data) {
  return {
    targetResourceId: data.resourceId,
    targetProject: data.accountId, // GCP uses project ID
    targetRegion: data.region,
    targetZone: data.zone || data.region,
    sirtID: data.sirtID || 'SIR-UNKNOWN',
    severity: data.severity,
    alertType: data.alertType,
    alertDescription: data.alertDescription,
    resourceType: data.resourceType,
    // GCP-specific fields
    resourceName: data.resourceArn || data.resourceId,
    projectId: data.accountId
  };
}

function buildAzurePayload(data) {
  return {
    targetResourceId: data.resourceId,
    targetSubscription: data.accountId,
    targetRegion: data.region,
    targetResourceGroup: data.resourceGroup || 'unknown',
    sirtID: data.sirtID || 'SIR-UNKNOWN',
    severity: data.severity,
    alertType: data.alertType,
    alertDescription: data.alertDescription,
    resourceType: data.resourceType,
    // Azure-specific fields
    resourceUri: data.resourceArn || data.resourceId,
    subscriptionId: data.accountId
  };
}

// ============================================
// STEP 4: Determine Function Name
// ============================================
let functionName = null;
let lambdaPayload = {};

if (provider === 'aws') {
  functionName = awsFunctionMap[data.resourceType] || 'contain-aws-unknown';
  lambdaPayload = buildAWSPayload(data);
} else if (provider === 'gcp') {
  functionName = gcpFunctionMap[data.resourceType] || 'contain-gcp-unknown';
  lambdaPayload = buildGCPPayload(data);
} else if (provider === 'azure') {
  functionName = azureFunctionMap[data.resourceType] || 'contain-azure-unknown';
  lambdaPayload = buildAzurePayload(data);
} else {
  functionName = 'contain-unknown-provider';
  lambdaPayload = {
    provider: provider,
    resourceType: data.resourceType,
    resourceId: data.resourceId,
    accountId: data.accountId,
    region: data.region,
    severity: data.severity,
    alertType: data.alertType,
    sirtID: data.sirtID || 'SIR-UNKNOWN'
  };
}

// ============================================
// STEP 5: Return Data
// ============================================
return [{
  json: {
    ...data,
    provider: provider,
    functionName: functionName,
    lambdaPayload: lambdaPayload,
    // For switch node routing
    providerType: provider,
    // Summary
    lambdaSummary: `Invoking ${functionName} for ${provider}:${data.resourceType} (${data.resourceId})`
  }
}];

// Get the incoming data from the cloud function/Lambda node
const data = $input.first().json;

// ============================================
// STEP 1: Extract Provider and Response
// ============================================
const provider = data.provider || 'unknown';
const response = data.response || data.body || data;

// ============================================
// STEP 2: Initialize Variables
// ============================================
let executionStatus = 'success';
let errorMessage = null;
let containmentDetails = {};
let parsedResponse = {};
let rawResponse = response;

// ============================================
// STEP 3: Parse Response Based on Provider
// ============================================

// 3a: AWS Lambda Response
if (provider === 'aws') {
  // AWS Lambda returns response in the body
  if (response.body) {
    try {
      parsedResponse = typeof response.body === 'string' ? JSON.parse(response.body) : response.body;
    } catch (error) {
      parsedResponse = { message: response.body };
    }
  } else {
    parsedResponse = response;
  }

  // Check for Lambda errors
  if (response.FunctionError) {
    executionStatus = 'failed';
    errorMessage = response.FunctionError;
  }
}

// 3b: GCP Cloud Function Response
else if (provider === 'gcp') {
  // GCP Cloud Functions return response directly
  if (response.body) {
    try {
      parsedResponse = typeof response.body === 'string' ? JSON.parse(response.body) : response.body;
    } catch (error) {
      parsedResponse = { message: response.body };
    }
  } else {
    parsedResponse = response;
  }

  // Check for GCP errors
  if (response.error || response.status === 'error') {
    executionStatus = 'failed';
    errorMessage = response.error || response.message || 'GCP Cloud Function error';
  }
}

// 3c: Azure Function Response
else if (provider === 'azure') {
  // Azure Functions return response directly
  if (response.body) {
    try {
      parsedResponse = typeof response.body === 'string' ? JSON.parse(response.body) : response.body;
    } catch (error) {
      parsedResponse = { message: response.body };
    }
  } else {
    parsedResponse = response;
  }

  // Check for Azure errors
  if (response.statusCode && response.statusCode >= 400) {
    executionStatus = 'failed';
    errorMessage = 'Azure Function returned status code: ' + response.statusCode;
  }
}

// 3d: Unknown Provider
else {
  // Generic response parsing
  if (response.body) {
    try {
      parsedResponse = typeof response.body === 'string' ? JSON.parse(response.body) : response.body;
    } catch (error) {
      parsedResponse = { message: response.body };
    }
  } else {
    parsedResponse = response;
  }
}

// ============================================
// STEP 4: Extract Containment Details
// ============================================
const status = parsedResponse.status || parsedResponse.result || parsedResponse.outcome || 'unknown';

if (status === 'success' || status === 'contained' || status === 'completed') {
  executionStatus = 'success';
  containmentDetails = {
    action: parsedResponse.action || parsedResponse.operation || 'contained',
    resourceId: parsedResponse.resourceId || parsedResponse.targetResourceId || data.resourceId,
    resourceType: parsedResponse.resourceType || data.resourceType,
    provider: provider,
    details: parsedResponse.details || parsedResponse.actions || parsedResponse.messages || [],
    timestamp: parsedResponse.timestamp || new Date().toISOString()
  };
} else if (status === 'failed' || status === 'error') {
  executionStatus = 'failed';
  errorMessage = parsedResponse.error || parsedResponse.message || parsedResponse.reason || 'Containment failed';
  containmentDetails = {
    action: parsedResponse.action || 'failed',
    resourceId: parsedResponse.resourceId || data.resourceId,
    resourceType: parsedResponse.resourceType || data.resourceType,
    provider: provider,
    details: parsedResponse.details || [],
    timestamp: new Date().toISOString()
  };
}

// ============================================
// STEP 5: Check for Manual Intervention
// ============================================
let needsManualIntervention = false;
let manualInterventionReason = '';

// Check various fields that might indicate manual intervention
if (parsedResponse.requiresManualIntervention || 
    parsedResponse.manualIntervention ||
    parsedResponse.needsManualIntervention ||
    parsedResponse.requiresHumanAction) {
  needsManualIntervention = true;
  manualInterventionReason = parsedResponse.manualInterventionReason || 
                            parsedResponse.reason || 
                            'Function indicates manual intervention required';
}

// Additional checks based on provider
if (provider === 'aws' && parsedResponse.FunctionError) {
  needsManualIntervention = true;
  manualInterventionReason = 'AWS Lambda error: ' + parsedResponse.FunctionError;
}

if (provider === 'gcp' && parsedResponse.error) {
  needsManualIntervention = true;
  manualInterventionReason = 'GCP Cloud Function error: ' + parsedResponse.error;
}

if (provider === 'azure' && parsedResponse.error) {
  needsManualIntervention = true;
  manualInterventionReason = 'Azure Function error: ' + parsedResponse.error;
}

// ============================================
// STEP 6: Extract Detailed Actions
// ============================================
let actionDetails = [];

// Try to extract detailed actions from various response formats
if (parsedResponse.actions && Array.isArray(parsedResponse.actions)) {
  actionDetails = parsedResponse.actions;
} else if (parsedResponse.details && Array.isArray(parsedResponse.details)) {
  actionDetails = parsedResponse.details;
} else if (parsedResponse.steps && Array.isArray(parsedResponse.steps)) {
  actionDetails = parsedResponse.steps;
} else if (parsedResponse.results && Array.isArray(parsedResponse.results)) {
  actionDetails = parsedResponse.results;
} else if (parsedResponse.messages && Array.isArray(parsedResponse.messages)) {
  actionDetails = parsedResponse.messages;
}

// If we have a single action string, convert to array
if (typeof parsedResponse.action === 'string' && actionDetails.length === 0) {
  actionDetails = [parsedResponse.action];
}

// ============================================
// STEP 7: Build Summary
// ============================================
let summary = '';

if (executionStatus === 'success') {
  summary = `✅ ${provider.toUpperCase()}/${data.resourceType} contained successfully`;
  if (actionDetails.length > 0) {
    summary += ' - ' + actionDetails.join(', ');
  }
} else {
  summary = `❌ Failed to contain ${provider.toUpperCase()}/${data.resourceType}`;
  if (errorMessage) {
    summary += ': ' + errorMessage;
  }
  if (needsManualIntervention) {
    summary += ' ⚠️ Manual intervention required!';
  }
}

// ============================================
// STEP 8: Build Slack Message
// ============================================
let slackText = '🚨 **Security Alert - ' + provider.toUpperCase() + ' Containment Result**\n\n';
slackText += '*SIR ID:* `' + (data.sirtID || 'SIR-UNKNOWN') + '`\n';
slackText += '*Provider:* ' + provider.toUpperCase() + '\n';
slackText += '*Status:* ' + (executionStatus === 'success' ? '✅ Success' : '❌ Failed') + '\n';
slackText += '*Summary:* ' + summary + '\n\n';
slackText += '*Resource Details:*\n';
slackText += '• Type: ' + data.resourceType + '\n';
slackText += '• ID: `' + data.resourceId + '`\n';
slackText += '• Account/Project: ' + data.accountId + '\n';
slackText += '• Region: ' + data.region + '\n';
slackText += '• Severity: ' + data.severity + '\n';
slackText += '• Alert: ' + data.alertType + '\n\n';
slackText += '*Function Details:*\n';
slackText += '• Function: `' + (data.functionName || 'unknown') + '`\n';
slackText += '• Timestamp: ' + new Date().toISOString() + '\n\n';

if (actionDetails.length > 0) {
  slackText += '*Containment Actions:*\n';
  for (let i = 0; i < actionDetails.length; i++) {
    slackText += '• ' + actionDetails[i] + '\n';
  }
  slackText += '\n';
}

if (needsManualIntervention) {
  slackText += '⚠️ **Manual Intervention Required!**\n';
  slackText += '*Reason:* ' + manualInterventionReason + '\n\n';
}

if (errorMessage) {
  slackText += '*Error:* ' + errorMessage + '\n\n';
}

// Add provider-specific information
if (provider === 'aws') {
  slackText += '*AWS Details:*\n';
  slackText += '• Request ID: ' + (parsedResponse.RequestId || 'N/A') + '\n';
  slackText += '• Function ARN: ' + (parsedResponse.FunctionArn || 'N/A') + '\n\n';
} else if (provider === 'gcp') {
  slackText += '*GCP Details:*\n';
  slackText += '• Function Name: ' + (data.functionName || 'N/A') + '\n';
  slackText += '• Project ID: ' + (data.accountId || 'N/A') + '\n\n';
} else if (provider === 'azure') {
  slackText += '*Azure Details:*\n';
  slackText += '• Function App: ' + (data.functionAppName || 'N/A') + '\n';
  slackText += '• Subscription ID: ' + (data.accountId || 'N/A') + '\n\n';
}

slackText += '🔗 *Containment completed* - Please verify resource is contained.';

// ============================================
// STEP 9: Build Provider-Specific Logs
// ============================================
let providerLog = {
  provider: provider,
  executionStatus: executionStatus,
  functionName: data.functionName,
  resourceId: data.resourceId,
  resourceType: data.resourceType,
  timestamp: new Date().toISOString()
};

// Add provider-specific fields
if (provider === 'aws') {
  providerLog.awsRequestId = parsedResponse.RequestId || 'N/A';
  providerLog.awsFunctionArn = parsedResponse.FunctionArn || 'N/A';
} else if (provider === 'gcp') {
  providerLog.gcpFunctionName = data.functionName;
  providerLog.gcpProjectId = data.accountId;
} else if (provider === 'azure') {
  providerLog.azureFunctionApp = data.functionAppName;
  providerLog.azureSubscriptionId = data.accountId;
}

// ============================================
// STEP 10: Return Data
// ============================================
return [{
  json: {
    // Original data (preserve for downstream nodes)
    ...data,

    // Execution results
    executionStatus: executionStatus,
    errorMessage: errorMessage,
    containmentDetails: containmentDetails,
    actionDetails: actionDetails,

    // Manual intervention flags
    needsManualIntervention: needsManualIntervention,
    manualInterventionReason: manualInterventionReason,

    // Parsed response
    parsedResponse: parsedResponse,
    rawResponse: rawResponse,

    // Provider-specific logs
    providerLog: providerLog,

    // Slack and summary
    slackText: slackText,
    summary: summary,

    // Timestamp
    timestamp: new Date().toISOString(),

    // Status for IF nodes
    status: executionStatus
  }
}];
